const leads = $input.all().map(i => i.json);
const by_stage = {};
const by_owner = {};
let hot = 0, warm = 0, cold = 0, total_score = 0, scored = 0;

for (const l of leads) {
  const s = l.Lead_Status || 'Без статусу';
  by_stage[s] = (by_stage[s] || 0) + 1;
  const o = l.Owner?.name || 'Без менеджера';
  by_owner[o] = (by_owner[o] || 0) + 1;
  // parse AI score from Description
  const m = String(l.Description || '').match(/AI Score:\s*(\d+)/);
  if (m) { total_score += Number(m[1]); scored++; }
  const temp = String(l.Description || '').match(/Temperature:\s*(\w+)/);
  if (temp) {
    const t = temp[1].toLowerCase();
    if (t === 'hot') hot++;
    else if (t === 'warm') warm++;
    else cold++;
  }
}

return [{ json: {
  total_leads: leads.length,
  hot_leads: hot,
  warm_leads: warm,
  cold_leads: cold,
  avg_score: scored > 0 ? Math.round(total_score / scored) : 0,
  by_stage,
  by_owner
}}];

const raw = $input.first().json?.output || JSON.stringify($input.first().json);
let r = {};
try {
  r = JSON.parse(raw.replace(/```json|```/g, '').trim());
} catch(e) {
  r = { raw: raw };
}

const problems = Array.isArray(r.problems) ? r.problems.map((p,i)=>`${i+1}. ${p}`).join('
') : r.problems || '';
const recs = Array.isArray(r.recommendations) ? r.recommendations.map((p,i)=>`${i+1}. ${p}`).join('
') : r.recommendations || '';
const errors = Array.isArray(r.top_agent_errors) ? r.top_agent_errors.map((p,i)=>`${i+1}. ${p}`).join('
') : '';

const text = `📊 CEO SALES REPORT — GrowthLab
${'─'.repeat(32)}

📅 Тиждень: ${new Date().toLocaleDateString('uk-UA')}

📈 МЕТРИКИ
Дзвінків: ${r.total_calls || '?'}
Конверсія: ${r.conversion_rate || '?'}
HOT лідів: ${r.hot_leads || '?'}
Середній score: ${r.avg_score || '?'}

📝 ПІДСУМОК
${r.week_summary || ''}

⚠️ ПРОБЛЕМИ
${problems}

🔴 ПОМИЛКИ АГЕНТА
${errors}

🍾 ПРІОРИТЕТНІ ЛІДИ
${r.priority_leads || ''}

✅ РЕКОМЕНДАЦІЇ
${recs}

🎯 ФОКУС НА НАСТУПНИЙ ТИЖДЕНЬ
${r.next_week_focus || ''}`;

return [{ json: { ...r, telegram_text: text } }];
